document.querySelectorAll(".el-form-group").forEach(e=>{const d=e.querySelector("input"),s=e.querySelector(".el-btn-show-password"),t=e.querySelector(".el-btn-mask-password");s.addEventListener("click",()=>{d.type="text",s.classList.add("el-hidden"),t.classList.remove("el-hidden")}),t.addEventListener("click",()=>{d.type="password",t.classList.add("el-hidden"),s.classList.remove("el-hidden")})});